### Define Supabase SSR Cookie Methods Interface and Implementations (TypeScript)

Source: https://context7.com/supabase/ssr/llms.txt

This code defines the `CookieMethodsBrowser`, `CookieMethodsServer`, and `CookieOptions` interfaces, establishing a contract for how cookies are accessed and manipulated in both browser and server SSR contexts. It provides concrete examples of browser-side cookie handling (e.g., `document.cookie` manipulation) and server-side handling (interacting with a request/response object), along with a sample `CookieOptions` object for configuring cookie properties.

```typescript
import type {
  CookieMethodsBrowser,
  CookieMethodsServer,
  CookieOptions
} from '@supabase/ssr'

// Browser cookie methods (both required)
const browserCookies: CookieMethodsBrowser = {
  getAll() {
    // Return all cookies as array of { name, value }
    const parsed = document.cookie.split('; ').reduce((acc, cookie) => {
      const [name, value] = cookie.split('=')
      return [...acc, { name, value: decodeURIComponent(value || '') }]
    }, [] as { name: string; value: string }[])
    return parsed
  },
  setAll(cookiesToSet) {
    // Set or remove multiple cookies at once
    cookiesToSet.forEach(({ name, value, options }) => {
      const serialized = `${name}=${encodeURIComponent(value || '')}`
      const opts = Object.entries(options || {})
        .map(([key, val]) => {
          if (key === 'maxAge') return `max-age=${val}`
          if (typeof val === 'boolean') return val ? key : ''
          return `${key}=${val}`
        })
        .filter(Boolean)
        .join('; ')
      document.cookie = opts ? `${serialized}; ${opts}` : serialized
    })
  }
}

// Server cookie methods (setAll optional for read-only contexts)
const serverCookies: CookieMethodsServer = {
  getAll() {
    // Must return ALL cookies, not just auth-related ones
    // Framework handles the actual cookie retrieval
    return request.cookies.getAll()
  },
  setAll(cookiesToSet) {
    // Optional in server components, required in middleware
    // Must set cookies on BOTH request and response
    cookiesToSet.forEach(({ name, value, options }) => {
      if (value === '') {
        // Empty value means delete the cookie
        response.cookies.delete(name)
      } else {
        response.cookies.set(name, value, options)
      }
    })
  }
}

// Cookie options interface
const cookieOptions: CookieOptions = {
  path: '/',
  sameSite: 'lax',
  httpOnly: false,
  maxAge: 400 * 24 * 60 * 60, // 400 days
  domain: '.example.com',
  secure: true
}
```

